#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code for RQ 6.9.8)
# =============================================================================
"""
Step ID: step02
Step Name: Compute Within-Schema Correlations at Key Timepoints
RQ: results/ch6/6.9.8
Generated: 2026-01-20

PURPOSE:
Compute Pearson correlations between accuracy and confidence within each schema condition
at key timepoints (T1, T2, T4). Apply Fisher Z transformation for CI computation and
Bonferroni correction for multiple comparisons (9 tests).

EXPECTED INPUTS:
- results/ch6/6.9.8/data/step01_reshaped_long.csv (1200 rows)
  Columns: UID, test, schema_condition, theta_accuracy, theta_confidence

EXPECTED OUTPUTS:
- results/ch6/6.9.8/data/step02_within_schema_correlations.csv (9 rows)
  Columns: schema_condition, timepoint, n, r, fisher_z, SE_z, CI_r_lower, CI_r_upper,
           p_uncorrected, p_bonferroni, sig_bonferroni

VALIDATION CRITERIA:
- Exactly 9 rows (3 schema conditions x 3 timepoints)
- r in [-1, 1], expected > 0.50
- p_bonferroni = p_uncorrected * 9
- Bonferroni alpha = 0.05/9 = 0.0056 (Decision D068)

g_code REASONING:
- Approach: Filter to T1/T2/T4, compute correlations per schema x timepoint, Fisher Z for CIs
- Why this approach: Standard correlation analysis with robust CI estimation
- Data flow: Load long data -> filter timepoints -> compute correlations -> apply transformations
- Expected performance: <10 seconds
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy.stats import pearsonr

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch6/6.9.8
LOG_FILE = RQ_DIR / "logs" / "step02_compute_correlations.log"
INPUT_FILE = RQ_DIR / "data" / "step01_reshaped_long.csv"
OUTPUT_FILE = RQ_DIR / "data" / "step02_within_schema_correlations.csv"

# Key timepoints for analysis
KEY_TIMEPOINTS = ['T1', 'T2', 'T4']

# Bonferroni correction parameters
N_TESTS = 9  # 3 schema conditions x 3 timepoints
ALPHA = 0.05
ALPHA_BONFERRONI = ALPHA / N_TESTS  # 0.0056

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console with flush."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 02: Compute Within-Schema Correlations")
        log(f"[INFO] Key timepoints: {KEY_TIMEPOINTS}")
        log(f"[INFO] Bonferroni correction: alpha = {ALPHA}/{N_TESTS} = {ALPHA_BONFERRONI:.4f}")

        # =====================================================================
        # STEP 1: Load and Filter Data
        # =====================================================================
        log("[LOAD] Loading long-format data...")
        df = pd.read_csv(INPUT_FILE)
        log(f"[LOADED] {len(df)} rows, {len(df.columns)} columns")

        log("[FILTER] Filtering to key timepoints...")
        df_key = df[df['test'].isin(KEY_TIMEPOINTS)].copy()
        log(f"[FILTERED] {len(df_key)} rows retained")

        # Verify expected row count
        expected_rows = 100 * 3 * 3  # 100 UIDs x 3 timepoints x 3 schema conditions
        if len(df_key) != expected_rows:
            log(f"[WARNING] Expected {expected_rows} rows, got {len(df_key)}")

        # =====================================================================
        # STEP 2: Compute Correlations for Each Schema x Timepoint
        # =====================================================================
        log("[ANALYSIS] Computing correlations...")

        results = []

        for schema in ['Common', 'Congruent', 'Incongruent']:
            for timepoint in KEY_TIMEPOINTS:
                # Filter to specific schema and timepoint
                subset = df_key[
                    (df_key['schema_condition'] == schema) &
                    (df_key['test'] == timepoint)
                ].copy()

                n = len(subset)

                if n < 3:
                    log(f"[WARNING] {schema} x {timepoint}: only {n} observations, skipping")
                    continue

                # Compute Pearson correlation
                r, p_uncorrected = pearsonr(
                    subset['theta_accuracy'],
                    subset['theta_confidence']
                )

                # Fisher Z transformation
                fisher_z = np.arctanh(r)
                SE_z = 1 / np.sqrt(n - 3)

                # 95% CI using Fisher Z
                z_critical = 1.96
                CI_z_lower = fisher_z - z_critical * SE_z
                CI_z_upper = fisher_z + z_critical * SE_z

                # Transform back to r scale
                CI_r_lower = np.tanh(CI_z_lower)
                CI_r_upper = np.tanh(CI_z_upper)

                # Bonferroni correction
                p_bonferroni = min(p_uncorrected * N_TESTS, 1.0)  # Cap at 1.0
                sig_bonferroni = p_bonferroni < ALPHA

                log(f"[COMPUTED] {schema:12s} x {timepoint}: r = {r:.3f} [CI: {CI_r_lower:.3f}, {CI_r_upper:.3f}], p = {p_uncorrected:.4f}, p_bonf = {p_bonferroni:.4f}")

                results.append({
                    'schema_condition': schema,
                    'timepoint': timepoint,
                    'n': n,
                    'r': r,
                    'fisher_z': fisher_z,
                    'SE_z': SE_z,
                    'CI_r_lower': CI_r_lower,
                    'CI_r_upper': CI_r_upper,
                    'p_uncorrected': p_uncorrected,
                    'p_bonferroni': p_bonferroni,
                    'sig_bonferroni': sig_bonferroni
                })

        df_corr = pd.DataFrame(results)
        log(f"[DONE] Computed {len(df_corr)} correlations")

        # =====================================================================
        # STEP 3: Validate Results
        # =====================================================================
        log("[VALIDATION] Checking correlation results...")

        errors = []

        # Check row count
        if len(df_corr) != N_TESTS:
            errors.append(f"Expected {N_TESTS} rows, got {len(df_corr)}")
        else:
            log("[PASS] Row count: 9")

        # Check correlation bounds
        if (df_corr['r'] < -1).any() or (df_corr['r'] > 1).any():
            errors.append("Correlation(s) out of bounds [-1, 1]")
        else:
            log("[PASS] All r in [-1, 1]")

        # Check positive correlations (expected)
        if (df_corr['r'] < 0).any():
            log("[WARNING] Some correlations negative (unexpected)")

        if (df_corr['r'] < 0.50).any():
            log("[WARNING] Some correlations < 0.50 (weaker than expected)")

        # Check SE_z positive
        if (df_corr['SE_z'] <= 0).any():
            errors.append("Found non-positive SE_z values")
        else:
            log("[PASS] All SE_z > 0")

        # Check SE_z approximately 0.10 (for n=100)
        se_mean = df_corr['SE_z'].mean()
        log(f"[INFO] Mean SE_z = {se_mean:.4f} (expected ~0.101 for n=100)")

        # Check p-value ranges
        if (df_corr['p_uncorrected'] < 0).any() or (df_corr['p_uncorrected'] > 1).any():
            errors.append("p_uncorrected out of range [0, 1]")
        if (df_corr['p_bonferroni'] < 0).any() or (df_corr['p_bonferroni'] > 1).any():
            errors.append("p_bonferroni out of range [0, 1]")
        else:
            log("[PASS] All p-values in [0, 1]")

        # Check CI ordering
        ci_violations = (df_corr['CI_r_lower'] >= df_corr['r']) | (df_corr['r'] >= df_corr['CI_r_upper'])
        if ci_violations.any():
            errors.append("CI bounds violate CI_lower < r < CI_upper")
        else:
            log("[PASS] All CIs properly ordered")

        # Check n = 100 for all rows
        if not (df_corr['n'] == 100).all():
            errors.append(f"Not all n = 100. Range: [{df_corr['n'].min()}, {df_corr['n'].max()}]")
        else:
            log("[PASS] All n = 100")

        # Report descriptive statistics
        log(f"[INFO] Correlation range: [{df_corr['r'].min():.3f}, {df_corr['r'].max():.3f}]")
        log(f"[INFO] Mean correlation: {df_corr['r'].mean():.3f} (SD = {df_corr['r'].std():.3f})")
        log(f"[INFO] Bonferroni-significant: {df_corr['sig_bonferroni'].sum()}/{len(df_corr)}")

        # =====================================================================
        # STEP 4: Save Output
        # =====================================================================
        if errors:
            log("[VALIDATION] FAIL - Errors detected:")
            for error in errors:
                log(f"  - {error}")
            raise ValueError(f"Validation failed with {len(errors)} error(s)")

        log("[VALIDATION] PASS - All checks passed")
        log("[INFO] Fisher Z transformation applied for CIs")
        log(f"[INFO] Bonferroni correction: alpha = {ALPHA_BONFERRONI:.4f} (Decision D068)")
        log("[INFO] Dual p-values reported (uncorrected and Bonferroni)")

        df_corr.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')
        log(f"[SAVED] Output: {OUTPUT_FILE}")

        log("[SUCCESS] Step 02 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        import traceback
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
